blocks.text:
act6_state = {
 entry_modifier: "none | high_completion | low_completion",
 main_package: "R1_destination | R2_stable | R3_repair",
 scores: {
 destination_clarity, life_stability, repair_ability, family_reality_handling,
 relationship_anchor, low_completion_risk, direction_fit, cost_awareness,
 resource_anxiety, avoidance_count, regret_level, ordinary_life_awareness
 },
 flags: [],
 club_arc: { main, secondary, trial, overcommitted, no_club_route },
 projected_ending: {
 ending_family, graduation_destination, completion_quality,
 ordinary_life_state, family_state, relationship_focus,
 regret_level, repair_state, final_chapter_allowed_adjustments
 }
}

function renderAct6Node(node, act6_state) {
 const phase = getTimePhase(node.id); // PRE, 01-05, 06-10, 11-15, 16-20
 const timeText = getPhaseIntroText(phase, act6_state.main_package);
 const dialogueAnchor = pickSeasonalDialogue(phase, act6_state.relationship_focus);
 const nodeText = renderNodeBody(node, act6_state);
 const choiceEcho = node.isChoice ? renderChoiceTimeEcho(node.choice, phase, act6_state) : "";

 return {
 time_phase: phase.key,
 semester: phase.semester,
 season: phase.season,
 season_bg_modifier: phase.visual_modifier,
 player_visible_text: [timeText, nodeText, dialogueAnchor, choiceEcho].filter(Boolean).join("

")
 };
}
